class Solution(object):
    def lastVisitedIntegers(self, nums):
        seen = []
        result = []
        consec = 0
        for x in nums:
            if x != -1:
                seen.append(x)
                consec = 0
            else:
                consec += 1
                idx = len(seen) - consec
                result.append(seen[idx] if idx >= 0 else -1)
        return result
